module RefModule(FSM_selector_C,
    FSM_sequential_state_reg_reg,
    clk_IBUF_BUFG,
    AR);output FSM_selector_C;
  output [1:0] FSM_sequential_state_reg_reg;
  input clk_IBUF_BUFG;
  input AR;

  reg FSM_selector_C; // Changed to reg type
  reg [1:0] FSM_sequential_state_reg_reg;

  always @(posedge clk_IBUF_BUFG) begin
    if (FSM_selector_C == 1'b1) begin
      FSM_sequential_state_reg_reg <= 2'b00;
    end else begin
      FSM_sequential_state_reg_reg <= FSM_sequential_state_reg_reg + AR;
    end
  end

    wire _n01 = FSM_sequential_state_reg_reg[0] ^ 2'b11[0];
  wire _n02 = FSM_sequential_state_reg_reg[1] ^ 2'b11[1];
  wire _n03 = FSM_sequential_state_reg_reg[2] ^ 2'b11[2];
  wire _n04 = FSM_sequential_state_reg_reg[3] ^ 2'b11[3];
  assign FSM_selector_C = ~_n01 & ~_n02 & ~_n03 & ~_n04;

endmodule
